import React from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { motion } from 'framer-motion';

const QueryAnalytics = ({ data }: { data: any }) => {
    if (!data || !data.historical_queries) return null;

    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="flex flex-col h-full"
        >
            <div className="flex justify-between items-center mb-6">
                <div className="flex items-center space-x-3">
                    <div className="w-1 h-3 bg-white" />
                    <h3 className="nothing-text-label">PATH_OPTIMIZATION_ENGINE</h3>
                </div>
                <div className="flex space-x-2">
                    <span className="text-[8px] text-white/20 font-mono tracking-[0.3em]">SAMPLING: 1000HZ</span>
                </div>
            </div>

            <div className="h-64 w-full">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={data.historical_queries} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                        <XAxis
                            dataKey="time"
                            stroke="#222"
                            fontSize={9}
                            tickLine={false}
                            axisLine={false}
                            dy={10}
                            fontFamily="JetBrains Mono"
                        />
                        <YAxis
                            stroke="#222"
                            fontSize={9}
                            tickLine={false}
                            axisLine={false}
                            fontFamily="JetBrains Mono"
                        />
                        <CartesianGrid strokeDasharray="1 15" stroke="#111" vertical={false} />
                        <Tooltip
                            contentStyle={{
                                backgroundColor: '#000',
                                border: '1px solid #2A2A2A',
                                borderRadius: '4px',
                                fontSize: '9px',
                                textTransform: 'uppercase',
                                fontFamily: 'JetBrains Mono'
                            }}
                            itemStyle={{ color: '#fff', padding: 0 }}
                            cursor={{ stroke: '#FFFFFF', strokeWidth: 0.5, strokeDasharray: '4 4' }}
                        />
                        <Line
                            type="stepAfter"
                            dataKey="gpt4"
                            stroke="#FFFFFF"
                            strokeWidth={1.5}
                            dot={false}
                            activeDot={{ r: 4, strokeWidth: 0, fill: '#FFFFFF' }}
                            name="PREMIUM"
                        />
                        <Line
                            type="stepAfter"
                            dataKey="sonnet"
                            stroke="#444"
                            strokeWidth={1}
                            strokeDasharray="4 4"
                            dot={false}
                            name="BALANCED"
                        />
                        <Line
                            type="stepAfter"
                            dataKey="phi3_local"
                            stroke="#222"
                            strokeWidth={1}
                            dot={false}
                            name="LOCAL"
                        />
                    </LineChart>
                </ResponsiveContainer>
            </div>

            <div className="mt-8 grid grid-cols-3 gap-4">
                {[
                    { label: 'Latency', value: '14.2ms', trend: 'OPTIMIZED' },
                    { label: 'Throughput', value: '842 r/s', trend: 'STABLE' },
                    { label: 'Precision', value: '0.999', trend: 'HIGH' }
                ].map((stat, i) => (
                    <div key={i} className="flex flex-col border-l border-white/5 pl-4">
                        <span className="nothing-text-label text-[8px] opacity-30">{stat.label}</span>
                        <div className="flex items-baseline space-x-2">
                            <span className="text-sm font-black font-mono">{stat.value}</span>
                            <span className="text-[7px] text-white/20">{stat.trend}</span>
                        </div>
                    </div>
                ))}
            </div>
        </motion.div>
    );
};

export default QueryAnalytics;
